// geminiService.ts

import { GoogleGenerativeAI, Part } from "@google/generative-ai";
import { PROSEMHeader, PROSEMRow } from "./types";

const LOCAL_STORAGE_API_KEY = "gemini_api_key";

// Function to safely extract JSON from a string
const extractJSON = (text: string): any => {
    try {
        // Remove markdown code block markers
        const jsonString = text.replace(/```json\n|```/g, '');
        // Parse the JSON string
        return JSON.parse(jsonString);
    } catch (error) {
        console.error("Failed to parse JSON:", error);
        // Fallback: If parsing fails, return an empty array or handle as needed
        return [];
    }
};

const hasApiKey = (): boolean => {
    return !!getApiKey();
};

const saveApiKeyToStorage = (key: string): void => {
    localStorage.setItem(LOCAL_STORAGE_API_KEY, key);
};

// Helper aman untuk mengambil API Key dengan prioritas yang benar
const getApiKey = (): string => {
    // 1. Cek Environment Variable (Prioritas untuk Deployment yang benar)
    if (process.env.API_KEY) {
        return process.env.API_KEY;
    }

    // 2. Cek LocalStorage (Prioritas untuk User yang input manual via UI)
    const storedKey = localStorage.getItem(LOCAL_STORAGE_API_KEY);
    if (storedKey) {
        return storedKey;
    }

    return '';
};

const createAIClient = () => {
    const apiKey = getApiKey();
    if (!apiKey) {
        throw new Error("API_KEY_MISSING"); // Error khusus untuk ditangkap UI
    }
    return new GoogleGenerativeAI({ apiKey });
};

// Helper untuk menangani error spesifik API Gemini
const handleGeminiError = (error: any) => {
    if (error.code === 401) {
        return "API key salah atau tidak valid.";
    }
    return "Terjadi kesalahan saat berkomunikasi dengan API Gemini.";
};

// Helper untuk mengubah data menjadi string dan menghindari errors
const safeToString = (data: any): string => {
    if (typeof data === "string") {
        return data;
    }
    if (typeof data === "number" || typeof data === "boolean") {
        return data.toString();
    }
    if (Array.isArray(data)) {
        return data.join(", "); // or more sophisticated handling as needed
    }
    return JSON.stringify(data); // Fallback: try to serialize
};

// Function to generate the PROSEM format string
export const generatePROSEM = async (messages: string[], options?: { temperature?: number }) => {
    try {
        const genAI = createAIClient();
        const model = genAI.getGenerativeModel({ model: "gemini-pro" });

        const formattedMessages = messages.map(msg => ({
            role: "user",
            parts: [{ text: msg }] as Part[]
        }));

        const result = await model.generateContent(formattedMessages, options);

        const response = result.response;
        const text = response.text();

        // Extract JSON from the response
        const extractedJSON = extractJSON(text);

        // Map the JSON data to PROSEM format
        let prosemString = "";
        if (Array.isArray(extractedJSON)) {
            prosemString += `<${PROSEMHeader}>\n`;
            extractedJSON.forEach((item: any) => {
                prosemString += `<${PROSEMRow}>`;
                for (const key in item) {
                    if (item.hasOwnProperty(key)) {
                        prosemString += `[${key}][${safeToString(item[key])}]`;
                    }
                }
                prosemString += `</${PROSEMRow}>\n`;
            });
            prosemString += `</${PROSEMHeader}>`;
        } else {
            prosemString = `Error: Response is not a valid JSON array. Received: ${text}`;
        }

        return prosemString;
    }

Tentu saja. Pertanyaan yang sangat bagus, dan jawabannya adalah: **Ya, Anda wajib memperbarui kode Google Apps Script Anda.**

Perubahan yang kita lakukan sebelumnya pada aplikasi (frontend) secara fundamental mengubah cara kerjanya.

*   **Sebelumnya:** Aplikasi di browser Anda memanggil API Gemini secara langsung.
*   **Sekarang:** Aplikasi di browser Anda mengirim permintaan ke Google Apps Script (backend). Google Apps Script-lah yang kini bertugas memanggil API Gemini dan mengirim hasilnya kembali.

Jadi, kode Google Apps Script Anda saat ini belum memiliki "kemampuan" untuk menerima permintaan baru ini dan berbicara dengan AI. Anda perlu menggantinya dengan kode baru yang berfungsi sebagai "jembatan" atau proxy yang aman.

### Langkah-Langkah Pembaruan

Ikuti 3 langkah penting ini:

**Langkah 1: Ganti Seluruh Kode**
Hapus semua isi file `Code.gs` Anda saat ini dan ganti dengan kode lengkap di bawah ini.

**Langkah 2: Simpan API Key Anda dengan Aman**
Kode baru ini akan mengambil API Key dari tempat yang aman bernama "Script Properties".

1.  Di editor Google Apps Script, klik ikon **Roda Gigi (Pengaturan Proyek)** di sebelah kiri.
2.  Di bagian bawah, akan ada area **"Properti Skrip"**. Klik tombol **"Tambahkan properti skrip"**.
3.  Untuk kolom **Properti**, masukkan `GEMINI_API_KEY`.
4.  Untuk kolom **Nilai**, masukkan API Key Gemini Anda yang valid.
5.  Klik **"Simpan properti skrip"**.

**Langkah 3: Lakukan Penerapan Ulang (Sangat Penting!)**
Setiap kali Anda mengubah kode Apps Script, perubahan tidak akan aktif sampai Anda melakukan penerapan ulang.
1.  Klik tombol biru **"Deploy"** di kanan atas.
2.  Pilih **"New deployment"**.
3.  Beri deskripsi (misalnya, "Update ke arsitektur proxy AI") lalu klik **"Deploy"**.
4.  **PENTING**: Anda mungkin perlu memberikan izin lagi. Ikuti saja alurnya.
5.  **Anda TIDAK perlu menyalin URL Aplikasi Web yang baru.** URL yang lama akan otomatis diperbarui dengan kode yang baru.

