/**
 * Main entry point for all web app requests.
 * Routes actions to the appropriate handler function.
 */
function doPost(e) {
  try {
    const params = JSON.parse(e.parameter.params);
    const action = e.parameter.action;

    const actionMap = {
      // AI Proxy Functions
      proxyGenerateTPs: proxyGenerateTPs,
      proxyGenerateATP: proxyGenerateATP,
      proxyGeneratePROTA: proxyGeneratePROTA,
      proxyGenerateKKTP: proxyGenerateKKTP,

      // Database Functions
      getTPsBySubject: getTPsBySubject,
      saveTP: saveTP,
      updateTP: updateTP,
      deleteTP: deleteTP,
      deleteATPsByTPId: deleteATPsByTPId,
      getATPsByTPId: getATPsByTPId,
      saveATP: saveATP,
      deleteATP: deleteATP,
      updateATP: updateATP,
      deletePROTAsByTPId: deletePROTAsByTPId,
      getPROTAsByTPId: getPROTAsByTPId,
      savePROTA: savePROTA,
      deletePROTA: deletePROTA,
      updatePROTA: updatePROTA,
      getKKTPsByATPId: getKKTPsByATPId,
      saveKKTP: saveKKTP,
      deleteKKTP: deleteKKTP,
      deleteKKTPsByATPId: deleteKKTPsByATPId,
      deleteKKTPsByTPId: deleteKKTPsByTPId,
      getPROSEMsByPROTAId: getPROSEMsByPROTAId,
      savePROSEM: savePROSEM,
      deletePROSEMsByPROTAId: deletePROSEMsByPROTAId,
      deletePROSEMsByTPId: deletePROSEMsByTPId,
    };

    if (actionMap[action]) {
      const data = actionMap[action](params);
      return sendSuccess(data);
    } else {
      return sendError(`Action "${action}" is not a valid action.`);
    }
  } catch (error) {
    Logger.log(`DoPost Error: ${error.message}\nStack: ${error.stack}`);
    return sendError(error.message);
  }
}


// ============================================================================
// AI PROXY FUNCTIONS
// ============================================================================

/**
 * Calls the Gemini API with a structured prompt.
 * @param {string} model The Gemini model to use.
 * @param {string} prompt The complete prompt text.
 * @returns {object} The parsed JSON object from the model's response.
 */
function callGenerativeAI(model, prompt, isJsonOutput = true) {
  const API_KEY = PropertiesService.getScriptProperties().getProperty('GEMINI_API_KEY');
  if (!API_KEY) {
    throw new Error('API Key Gemini belum diatur di Properti Skrip. Mohon konfigurasikan GEMINI_API_KEY.');
  }

  const url = `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${API_KEY}`;

  const payload = {
    contents: [{ parts: [{ text: prompt }] }],
    generationConfig: isJsonOutput ? {
      responseMimeType: "application/json",
      temperature: 0.5,
      topP: 0.95,
      topK: 40
    } : {
      temperature: 0.5,
      topP: 0.95,
      topK: 40
    }
  };

  const options = {
    method: 'post',
    contentType: 'application/json',
    payload: JSON.stringify(payload),
    muteHttpExceptions: true
  };

  const response = UrlFetchApp.fetch(url, options);
  const responseCode = response.getResponseCode();
  const responseBody = response.getContentText();

  if (responseCode === 200) {
    const jsonResponse = JSON.parse(responseBody);
    if (jsonResponse.candidates && jsonResponse.candidates.length > 0) {
      const text = jsonResponse.candidates[0].content.parts[0].text;
      if (!text) {
        throw new Error("Respons dari AI kosong. Ini mungkin karena filter keamanan. Coba ubah input Anda.");
      }
      return isJsonOutput ? JSON.parse(text) : text;
    } else {
       // Handle safety blocks or empty responses
       const blockReason = jsonResponse.promptFeedback ? jsonResponse.promptFeedback.blockReason : 'Tidak diketahui';
       throw new Error(`Respons dari AI terblokir karena alasan keamanan: ${blockReason}. Harap periksa kembali input Anda.`);
    }
  } else {
    Logger.log(`AI Error (Code: ${responseCode}): ${responseBody}`);
    const errorDetails = JSON.parse(responseBody).error;
    throw new Error(`Gagal menghubungi AI: ${errorDetails.message} (Status: ${errorDetails.status})`);
  }
}

function proxyGenerateTPs(params) {
  const { subject, grade, cpElements, additionalNotes } = params.input;
