          "Teks tujuan pembelajaran pertama...",
          "Teks tujuan pembelajaran kedua..."
        ]
      },
      {
        "subMateri": "Nama Sub-Materi 1.2",
        "tps": ["Teks tujuan pembelajaran..."]
      }
    ]
  },
  {
    "semester": "Ganjil" atau "Genap",
    "materi": "Nama Materi Pokok Kedua",
    "subMateriGroups": [
      {
        "subMateri": "Nama Sub-Materi 2.1",
        "tps": ["Teks tujuan pembelajaran..."]
