]
`;
  return callGenerativeAI('gemini-1.5-flash', prompt);
}

function proxyGenerateATP(params) {
    const { subject, grade, tpGroups } = params.tpData;

    let tpCounter = 1;
    let materiCounter = 1;
    const formattedTPs = tpGroups.map(group => {
        const subMateriText = group.subMateriGroups.map(subGroup => {
            const tpsText = subGroup.tps.map(tp => `  - TP ${tpCounter++}: ${tp}`).join('\n');
