function sendSuccess(data) {
  const response = { status: 'success', data: data };
  return ContentService.createTextOutput(JSON.stringify(response))
    .setMimeType(ContentService.MimeType.JSON);
}

function sendError(message) {
  const response = { status: 'error', message: message };
  return ContentService.createTextOutput(JSON.stringify(response))
    .setMimeType(ContentService.MimeType.JSON);
}

function sheetToObjects(sheet) {
  if (!sheet) return [];
  const data = sheet.getDataRange().getValues();
  if (data.length < 2) return [];
  const headers = data[0];
  return data.slice(1).map(row => {
    const obj = {};
    headers.forEach((header, i) => { obj[header] = row[i]; });
    return obj;
  });
}

function saveRow(sheet, data, idPrefix) {
  if (!sheet) throw new Error("Sheet not found.");
  const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
  const newRow = headers.map(header => data[header] || '');
  sheet.appendRow(newRow);
  return data;
}

function updateRow(sheet, id, data) {
  if (!sheet) throw new Error("Sheet not found.");
  const dataObjects = sheetToObjects(sheet);
  const rowIndex = dataObjects.findIndex(row => row.id === id);
  if (rowIndex === -1) throw new Error("Row not found for update.");

  const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
  headers.forEach((header, i) => {
    if (data.hasOwnProperty(header)) {
      sheet.getRange(rowIndex + 2, i + 1).setValue(data[header]);
    }
  });
  return sheetToObjects(sheet)[rowIndex];
}

function deleteRow(sheet, id) {
  if (!sheet) throw new Error("Sheet not found.");
  const dataObjects = sheetToObjects(sheet);
  const rowIndex = dataObjects.findIndex(row => row.id === id);
  if (rowIndex !== -1) {
    sheet.deleteRow(rowIndex + 2);
    return { success: true };
  }
  return { success: false, message: "Row not found." };
}

function getRowsByFilter(sheet, filterKey, filterValue) {
  if (!sheet) return [];
  const data = sheetToObjects(sheet);
  return data.filter(row => row[filterKey] === filterValue);
}


